// // This module implements a 4-bit shift register with parallel load.
// It has the following inputs and outputs:
// - clk: a clock input
// - load: a synchronous active-low input that loads the input data into the shift register on the falling edge of the clock
// - in: a 4-bit input that is loaded into the shift register when load is low
// - shift: a synchronous active-low input that shifts the data in the shift register one bit to the right on the falling edge of the clock
// - out: a 4-bit output that represents the current state of the shift register
module shift_register(clk, load, in, shift, out);
    input clk, load, shift;
    input [3:0] in;
    output [3:0] out;
    reg [3:0] reg_out;

    always @(posedge clk) begin
        if (load) begin
            reg_out <= in;
        end else if (shift) begin
            reg_out <= {reg_out[2:0], 1'b0};
        end
    end

    assign out = reg_out;
endmodule

